import React, { useState } from 'react';
import { Link, NavLink } from 'react-router-dom';
import axios from 'axios';

const api = axios.create({baseURL: 'http://localhost:5000'});


function Home() {
    const [setIsLoggedIn] = useState(false);
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [messageType, setMessageType] = useState('');

    const showMessage = (text, type) => {
        setMessage(text);
        setMessageType(type);
        setTimeout(() => {
        setMessage('');
        setMessageType('');
        }, 5000);
    };

    const handleLogout = async () => {
        setLoading(true);
        setMessage('');
        setMessageType('');

        try {
        const response = await api.post('/logout');

        if (response.status === 200) {
            setIsLoggedIn(false);
        }
        } catch (error) {
        showMessage('Ошибка при выходе', 'error');
        } finally {
        setLoading(false);
        }
    };

    return(
    <div>
        <nav className="navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0">
            <div className="container-fluid py-2">
                <Link className="navbar-brand fs-3 fw-bold" to="/">roads_admin</Link>
                <Link className="navbar-brand fs-3 fw-bold" to="/">
                    <button 
                        onClick={handleLogout} 
                        className="logout-button"
                        disabled={loading}
                    >
                        {loading ? (
                        <>
                            <span className="spinner"></span>
                            Выход...
                        </>
                        ) : 'Выйти'}
                    </button>
                {message && (
                    <div className={`message ${messageType}-message`}>
                    {message}
                    </div>
                )}
                </Link>
            </div>
            <div className="container-fluid bg-dark py-2">
                <div className="navbar-nav flex-row">
                    <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/" end> Главная </NavLink>
                    <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/roads" end> Дороги </NavLink>
                    <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/sings" end> Дорожные знаки </NavLink>
                    <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/roads/sings" end> Знаки на дорогах </NavLink>
                </div>
            </div>
        </nav>
        <h1>Главная страница</h1>
    </div>
    );
}

export default Home;
